func factorial(n int) (int, error) {
	if n < 0 {
		return 0, fmt.Errorf("factorial not defined for negative numbers")
	}
	if n == 0 || n == 1 {
		return 1, nil
	}
	result, err := factorial(n - 1)
	if err != nil {
		return 0, err
	}
	if result > (1<<31-1)/n {
		return 0, fmt.Errorf("factorial calculation would overflow")
	}
	return n * result, nil
}

func main() {
	reader := bufio.NewReader(os.Stdin)
	fmt.Print("Enter a number to calculate its factorial: ")
	input, err := reader.ReadString('\n')
	if err != nil {
		fmt.Println("Error reading input:", err)
		return
	}

	input = strings.TrimSpace(input)
	num, err := strconv.Atoi(input)
	if err != nil {
		fmt.Println("Invalid input. Please enter a valid integer:", err)
		return
	}

	result, err := factorial(num)
	if err != nil {
		fmt.Println("Error calculating factorial:", err)
		return
	}

	fmt.Println("Factorial of", num, "is:", result)
}

