        switch (element.ValueKind)
        {
            case JsonValueKind.Object:
                var obj = new System.Collections.Generic.Dictionary<string, object>();
                foreach (var property in element.EnumerateObject())
                {
                    obj[property.Name] = ConvertJsonElementToObject(property.Value);
                }
                return obj;

            case JsonValueKind.Array:
                var list = new System.Collections.Generic.List<object>();
                foreach (var item in element.EnumerateArray())
                {
                    list.Add(ConvertJsonElementToObject(item));
                }
                return list;

            case JsonValueKind.String:
                return element.GetString();

            case JsonValueKind.Number:
                if (element.TryGetInt32(out int intValue))
                    return intValue;
                if (element.TryGetInt64(out long longValue))
                    return longValue;
                return element.GetDouble();

            case JsonValueKind.True:
                return true;

            case JsonValueKind.False:
                return false;

            case JsonValueKind.Null:
                return null;

            default:
                return null;
        }
    }

    static void ModifyJsonValue(object jsonObject, string key, string newValue)
    {
        if (jsonObject is Dictionary<string, object> dict)
        {
            foreach (var kvp in dict)
            {
                if (kvp.Key == key)
                {
                    // Try to preserve the type
                    if (kvp.Value is int)
                        dict[key] = int.Parse(newValue);
                    else if (kvp.Value is long)
                        dict[key] = long.Parse(newValue);
                    else if (kvp.Value is double)
                        dict[key] = double.Parse(newValue);
                    else if (kvp.Value is bool)
                        dict[key] = bool.Parse(newValue);
                    else
                        dict[key] = newValue;
                    return;
                }
                else if (kvp.Value is Dictionary<string, object> || kvp.Value is List<object>)
                {
                    ModifyJsonValue(kvp.Value, key, newValue);
                }
            }
        }
        else if (jsonObject is List<object> list)
        {
            foreach (var item in list)
            {
                if (item is Dictionary<string, object> || item is List<object>)
                {
                    ModifyJsonValue(item, key, newValue);
                }
            }
        }
    }
}

