import (
	"fmt"
	"net/http"
	"sync"
)

type Result struct {
	URL     string
	Success bool
	Error   error
}

func go(urls []string) []Result {
	var wg sync.WaitGroup
	results := make([]Result, len(urls))

	for i, url := range urls {
		wg.Add(1)

		go func(index int, reqURL string) {
			defer wg.Done()

			resp, err := http.Get(reqURL)
			if err != nil {
				results[index] = Result{
					URL:     reqURL,
					Success: false,
					Error:   err,
				}
				return
			}
			defer resp.Body.Close()

			if resp.StatusCode >= 200 && resp.StatusCode < 300 {
				results[index] = Result{
					URL:     reqURL,
					Success: true,
				}
			} else {
				results[index] = Result{
					URL:     reqURL,
					Success: false,
					Error:   fmt.Errorf("non-success status code: %d", resp.StatusCode),
				}
			}
		}(i, url)
	}

	wg.Wait()
	return results
}

func main() {
	urls := []string{
		"https://www.google.com",
		"https://www.github.com",
		"https://www.invalid-domain-example.com",
	}

	results := go(urls)

	successful := 0
	errors := make(map[string]error)

	for _, result := range results {
		if result.Success {
			successful++
		} else if result.Error != nil {
			errors[result.URL] = result.Error
		}
	}

	fmt.Printf("Total requests: %d\n", len(results))
	fmt.Printf("Successful requests: %d\n", successful)
	fmt.Printf("Failed requests: %d\n", len(errors))

	if len(errors) > 0 {
		fmt.Println("Errors encountered:")
		for url, err := range errors {
			fmt.Printf("  %s: %v\n", url, err)
		}
	}
}

