use std::env;
use std::process::{Command, exit};
use std::error::Error;

fn main() -> Result<(), Box<dyn Error>> {
    // Skip the program name (first argument)
    let args: Vec<String> = env::args().skip(1).collect();

    if args.is_empty() {
        println!("Usage: command_tool <command> [args...]");
        println!("Example: command_tool ls -la");
        exit(1);
    }

    // The first argument is the command to execute
    let command_name = &args[0];

    // Process remaining arguments using map function
    let command_args: Vec<String> = args.iter()
        .skip(1)
        .map(|arg| arg.to_string())
        .collect();

    println!("Executing: {} with arguments: {:?}", command_name, command_args);

    // Execute the command with its arguments
    let output = Command::new(command_name)
        .args(&command_args)
        .output()?;

    // Handle command output
    if output.status.success() {
        // Process successful output with map
        String::from_utf8(output.stdout)?
            .lines()
            .map(|line| line.trim())
            .filter(|line| !line.is_empty())
            .for_each(|line| println!("{}", line));

        Ok(())
    } else {
        // Process error output with map
        let error_message = String::from_utf8(output.stderr)?
            .lines()
            .map(|line| format!("Error: {}", line))
            .collect::<Vec<String>>()
            .join("\n");

        println!("{}", error_message);
        println!("Command failed with exit code: {}", output.status);

        exit(output.status.code().unwrap_or(1));
    }
}
