import (
	"sync"
)

func sumConcurrently(numbers []int, numGoroutines int) int {
	if len(numbers) == 0 {
		return 0
	}

	if numGoroutines <= 0 {
		numGoroutines = 1
	}

	// Adjust number of goroutines if array is smaller
	if len(numbers) < numGoroutines {
		numGoroutines = len(numbers)
	}

	var wg sync.WaitGroup
	resultChan := make(chan int, numGoroutines)

	// Calculate segment size
	segmentSize := len(numbers) / numGoroutines

	// Launch goroutines
	for i := 0; i < numGoroutines; i++ {
		wg.Add(1)

		// Calculate start and end indices for this segment
		start := i * segmentSize
		end := start + segmentSize

		// Handle the last segment which might be larger
		if i == numGoroutines-1 {
			end = len(numbers)
		}

		// Process segment in goroutine
		go func(start, end int) {
			defer wg.Done()

			sum := 0
			for j := start; j < end; j++ {
				sum += numbers[j]
			}

			resultChan <- sum
		}(start, end)
	}

	// Close channel after all goroutines complete
	go func() {
		wg.Wait()
		close(resultChan)
	}()

	// Aggregate results
	totalSum := 0
	for partialSum := range resultChan {
		totalSum += partialSum
	}

	return totalSum
}

